  ('a1e10900-0000-4000-8000-000000000000','a1e00000-0000-4000-8000-000000000000','確認テスト ─ 3C/SWOT/5フォース','quiz',NULL,NULL,NULL,3,2),
  ('a1e20900-0000-4000-8000-000000000000','a1e00000-0000-4000-8000-000000000000','確認テスト ─ 自社の戦略を「読める」ようになる','quiz',NULL,NULL,NULL,3,4)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1e10900-0000-4000-8000-000000000000','本文が言う「フレームワークの本質」を一行で表したものはどれか。','抜け漏れなく見るための、共通のものさしである','名前と略語を正確に暗記するための道具である','きれいな表を作って資料に貼るための様式である','会議で分析したと言うための見栄えのいい一枚である','A',0),
('a1e10900-0000-4000-8000-000000000000','本文が示す3Cの使い方で、正しい順番はどれか。','自社から書き始め、最後に市場・顧客を見る','市場・顧客を先に見て、自社は最後でいい','競合を最初に見て、市場・顧客は書かない','3つを厳密に点数化してから順位をつける','B',1),
('a1e10900-0000-4000-8000-000000000000','本文が挙げる「失敗①(枠を埋めることが目的になる)」の修正として正しいものはどれか。','3C・SWOT・5フォースを一つの企画に全部かける','分類で迷ったら重要な要素を枠から捨てる','埋める前に「何を知りたいのか」問いを決める','5つの圧力を精密に点数化してから埋める','C',2),
('a1e20900-0000-4000-8000-000000000000','本文が言う「戦略の本質」を一行で表したものはどれか。','やることリストを、もれなく全部並べることである','限られた資源を、どこに集中させるかの選択である','経営方針のスローガンを、朝礼で復唱することである','上が描いた指示を、忠実に実行することである','B',0),
('a1e20900-0000-4000-8000-000000000000','本文が「いい戦略」と「ただのスローガン」を見分ける基準として挙げるものはどれか。','きれいな言葉で語られているか','社長が熱を込めて語っているか','捨てるもの(痛みを伴う選択)が隠れているか','中期計画の冊子に印刷されているか','C',1),
('a1e20900-0000-4000-8000-000000000000','本文が示す「手順4(現場の言葉に翻訳して部下に伝える)」の注意点はどれか。','経営の言葉を、そのまま部下に渡す','翻訳のとき「なぜ」を省かない','生産量を増やすことを、最優先の目標にする','批判で終わらせ、行動には触れない','B',2);
